import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import "./App.css";

const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNuYWt5YW1keWRxeGlzdGRhdmZnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTM5NDIzNTEsImV4cCI6MjA2OTUxODM1MX0.mAVSru38H63peSy0iH6nDdJ0WBxBwQcoVJwYMy9UKBo";
const supabase = createClient(supabaseUrl, supabaseKey);

const columnOrder = [
    "PROJE ADI", "TALEP", "TEDARńįK", "VERńįLEMEYEN",
    "REEL TALEP", "REEL TEDARńįK", "REEL VERńįLMEYEN",
    "TED. %", "SPOT", "FńįLO", "TESńįSTE", "GELECEK", "Y√úKLENDńį",
    "HEDEF √úST√ú SEFER", "HEDEF ALTI SEFER", "HEDEF SEFER", "HEDEFSńįZ SEFER"
];

const ALLOWED_PROJECTS = new Set([
    "BUNGE L√úLEBURGAZ FTL", "REKA FTL", "EKSUN GIDA FTL", "SARUHAN FTL",
    "PEPSńį FTL", "MUTLU MAKARNA SPOT FTL", "TEKńįRDAńě UN FTL", "AYDINLI MODA FTL",
    "ADKOTURK FTL", "ADKOTURK FTL ENERJńį ńį√áECEńěńį", "SGS FTL", "BSH FTL",
    "ALTERNA GIDA FTL", "DERYA OFńįS FTL", "SAPRO FTL", "MARMARA CAM FTL",
    "FAKńįR FTL", "MODERN KARTON FTL", "K√ú√á√úKBAY FTL"
]);

const projectMergeMap = {
    "BUNGE L√úLEBURGAZ FTL": ["BUNGE L√úLEBURGAZ FTL", "BUNGE DńįLOVASI-REYSAŇě", "BUNGE PALET"],
    "MODERN KARTON FTL": ["MODERN KARTON-PACKON", "MODERN KARTON-NńįŇěASTA"]
};

function App() {
    const [data, setData] = useState([]);
    const [odakData, setOdakData] = useState([]);

    useEffect(() => {
        async function fetchSupabaseData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) {
                console.error("Supabase veri √ßekme hatasńĪ:", error);
                return;
            }

            if (data && data.json_data) {
                setData(data.json_data);
            }
        }

        fetchSupabaseData();
    }, []);

    useEffect(() => {
        async function fetchOdakData() {
            const today = new Date().toISOString().split("T")[0];
            const payload = {
                startDate: `${today}T00:00:00`,
                endDate: `${today}T23:59:59`,
                userId: 1
            };

            try {
                const response = await fetch("/api/tmsorders/getall", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization: "Bearer 49223653afa4b7e22c3659762c835dcdef9725a401e928fd46f697be8ea2597273bf4479cf9d0f7e5b8b03907c2a0b4d58625692c3e30629ac01fc477774de75"
                    },
                    body: JSON.stringify(payload)
                });

                const result = await response.json();
                const items = Array.isArray(result.Data) ? result.Data : [];

                const filteredItems = items.filter((item) => {
                    const pickupDate = item.PickupDate?.split("T")[0];
                    return (
                        pickupDate === today &&
                        item.OrderStatu !== 200 &&
                        item.TMSVehicleRequestDocumentNo &&
                        item.ProjectName
                    );
                });

                const projectMap = new Map();

                filteredItems.forEach((item) => {
                    const project = item.ProjectName;
                    const despatch = !!item.TMSDespatchDocumentNo;
                    const vehicleNo = item.TMSVehicleRequestDocumentNo;
                    const key = `${project}-${vehicleNo}`;

                    if (!projectMap.has(project)) {
                        projectMap.set(project, {
                            ProjectName: project,
                            "REEL TALEP": 0,
                            "REEL TEDARńįK": 0,
                            "REEL VERńįLMEYEN": 0,
                            _seenKeys: new Set()
                        });
                    }

                    const projData = projectMap.get(project);
                    if (!projData._seenKeys.has(key)) {
                        projData._seenKeys.add(key);
                        projData["REEL TALEP"] += 1;
                        if (despatch) projData["REEL TEDARńįK"] += 1;
                        else projData["REEL VERńįLMEYEN"] += 1;
                    }
                });

                const finalData = Array.from(projectMap.values()).map((p) => {
                    delete p._seenKeys;
                    return p;
                });

                setOdakData(finalData.filter((p) => ALLOWED_PROJECTS.has(p.ProjectName)));
            } catch (err) {
                console.error("Odak API hatasńĪ:", err);
            }
        }

        fetchOdakData();
    }, []);

    useEffect(() => {
        if (data.length === 0 || odakData.length === 0) return;

        const header = data[0];
        const rows = data.slice(1);

        const updatedRows = rows.map((row) => ({
            ...row,
            "REEL TALEP": 0,
            "REEL TEDARńįK": 0,
            "REEL VERńįLMEYEN": 0
        }));

        odakData.forEach((odak) => {
            const groupList = projectMergeMap[odak.ProjectName] || [odak.ProjectName];

            updatedRows.forEach((row) => {
                const projeAdi = row["PROJE ADI"]?.trim();
                if (groupList.includes(projeAdi)) {
                    row["REEL TALEP"] = odak["REEL TALEP"] ?? 0;
                    row["REEL TEDARńįK"] = odak["REEL TEDARńįK"] ?? 0;
                    row["REEL VERńįLMEYEN"] = odak["REEL VERńįLMEYEN"] ?? 0;
                }
            });
        });

        setData([header, ...updatedRows]);
    }, [odakData]);

    return (
        <div className="app-container">
            <div className="section">
                <h2>ūüüĘ Supabase + Odak Verileri</h2>
                {data.length > 0 ? (
                    <div className="table-wrapper">
                        <table className="styled-table">
                            <thead>
                                <tr>
                                    {columnOrder.map((col) => (
                                        <th key={col}>{col}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody>
                                {data.slice(1).map((row, idx) => (
                                    <tr key={idx}>
                                        {columnOrder.map((col, colIdx) => {
                                            let val = row[col] ?? 0;
                                            let style = {};

                                            if (col === "TED. %") {
                                                const num = parseFloat(val);
                                                if (!isNaN(num)) {
                                                    const pct = Math.round(num * 100);
                                                    val = `%${pct}`;
                                                    style = {
                                                        fontWeight: "bold",
                                                        color: pct < 70 ? "#e74c3c" : pct < 90 ? "#f39c12" : "#27ae60"
                                                    };
                                                }
                                            }

                                            if (
                                                ["HEDEF √úST√ú SEFER", "HEDEF ALTI SEFER", "HEDEF SEFER"].includes(col)
                                            ) {
                                                const parsed = parseFloat(val);
                                                if (!isNaN(parsed)) {
                                                    val = `${parsed.toLocaleString("tr-TR")} ‚āļ`;
                                                    if (col === "HEDEF √úST√ú SEFER") {
                                                        style = {
                                                            fontWeight: "bold",
                                                            color: parsed > 0 ? "#27ae60" : "#e74c3c"
                                                        };
                                                    }
                                                }
                                            }

                                            return (
                                                <td key={colIdx} style={style}>
                                                    {val}
                                                </td>
                                            );
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <p className="loading">Y√ľkleniyor...</p>
                )}
            </div>
        </div>
    );
}

export default App;
